#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*x + R) - (*y + R);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, L, R;
        scanf("%d %d %d", &N, &L, &R);
        int x[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &x[i]);
        }
        qsort(x, N, sizeof(int), compare);
        int last_end = -1;
        int moved = 0;
        for (int i = 0; i < N; i++) {
            if (x[i] < 0 || x[i] + R > L) {
                moved++;
            } else if (last_end != -1 && x[i] < last_end) {
                moved++;
            } else {
                last_end = x[i] + R;
            }
        }
        printf("%d\n", moved);
    }
    return 0;
}

