import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int L = sc.nextInt();
            int R = sc.nextInt();
            int[] x = new int[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextInt();
            }
            Arrays.sort(x);
            int last_end = -1;
            int moved = 0;
            for (int i = 0; i < N; i++) {
                if (x[i] < 0 || x[i] + R > L) {
                    moved++;
                } else if (last_end != -1 && x[i] < last_end) {
                    moved++;
                } else {
                    last_end = x[i] + R;
                }
            }
            System.out.println(moved);
        }
    }
}

